-- Get first user and first group
SELECT @user1_id := id FROM users ORDER BY id LIMIT 1;
SELECT @group1_id := id FROM work_groups ORDER BY id LIMIT 1;
SELECT @group2_id := id FROM work_groups ORDER BY id LIMIT 1 OFFSET 1;
SELECT @cost_center1_id := id FROM cost_centers ORDER BY id LIMIT 1;

-- Clear existing permissions
DELETE FROM user_permissions;

-- Example 1: User 1 - Full access to first group
INSERT INTO user_permissions (user_id, permission, scope_type, scope_id, granted_by, granted_at)
SELECT @user1_id, 'view', 'work_group', @group1_id, @user1_id, NOW()
WHERE @user1_id IS NOT NULL AND @group1_id IS NOT NULL;

INSERT INTO user_permissions (user_id, permission, scope_type, scope_id, granted_by, granted_at)
SELECT @user1_id, 'create', 'work_group', @group1_id, @user1_id, NOW()
WHERE @user1_id IS NOT NULL AND @group1_id IS NOT NULL;

INSERT INTO user_permissions (user_id, permission, scope_type, scope_id, granted_by, granted_at)
SELECT @user1_id, 'update', 'work_group', @group1_id, @user1_id, NOW()
WHERE @user1_id IS NOT NULL AND @group1_id IS NOT NULL;

INSERT INTO user_permissions (user_id, permission, scope_type, scope_id, granted_by, granted_at)
SELECT @user1_id, 'delete', 'work_group', @group1_id, @user1_id, NOW()
WHERE @user1_id IS NOT NULL AND @group1_id IS NOT NULL;

-- Example 2: User 1 - View-only access to second group
INSERT INTO user_permissions (user_id, permission, scope_type, scope_id, granted_by, granted_at)
SELECT @user1_id, 'view', 'work_group', @group2_id, @user1_id, NOW()
WHERE @user1_id IS NOT NULL AND @group2_id IS NOT NULL;

-- Example 3: User 1 - Cost center permissions
INSERT INTO user_permissions (user_id, permission, scope_type, scope_id, granted_by, granted_at)
SELECT @user1_id, 'view', 'cost_center', @cost_center1_id, @user1_id, NOW()
WHERE @user1_id IS NOT NULL AND @cost_center1_id IS NOT NULL;

INSERT INTO user_permissions (user_id, permission, scope_type, scope_id, granted_by, granted_at)
SELECT @user1_id, 'export', 'cost_center', @cost_center1_id, @user1_id, NOW()
WHERE @user1_id IS NOT NULL AND @cost_center1_id IS NOT NULL;

-- Example 4: User 1 - Payroll period permissions
INSERT INTO user_permissions (user_id, permission, scope_type, scope_id, granted_by, granted_at)
SELECT @user1_id, 'view', 'payroll_period', '2026-01', @user1_id, NOW()
WHERE @user1_id IS NOT NULL;

INSERT INTO user_permissions (user_id, permission, scope_type, scope_id, granted_by, granted_at)
SELECT @user1_id, 'create', 'payroll_period', '2026-01', @user1_id, NOW()
WHERE @user1_id IS NOT NULL;

-- Show results
SELECT 
  u.full_name AS user_name,
  up.permission,
  up.scope_type,
  up.scope_id,
  up.granted_at
FROM user_permissions up
JOIN users u ON u.id = up.user_id
ORDER BY u.full_name, up.scope_type, up.scope_id, up.permission;

